/*
 * Secure Cloud Database Connection - C Implementation
 * Demonstrates SSL/TLS encrypted connection to cloud databases
 * Compile with: gcc -o secure_db secure_db.c -lssl -lcrypto -lpq
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>
#include <openssl/ssl.h>
#include <openssl/err.h>

/* Database connection configuration structure */
typedef struct {
 const char *host;
 const char *port;
 const char *database;
 const char *user;
 const char *password;
 const char *ssl_mode;
 const char *ssl_cert;
 const char *ssl_key;
 const char *ssl_root_cert;
} DBConfig;

/* Initialize OpenSSL for secure connections */
void init_ssl(void) {
 SSL_library_init();
 SSL_load_error_strings();
 OpenSSL_add_all_algorithms();
}

/* Configure SSL connection parameters */
void configure_ssl(PGconn *conn) {
 /* Set SSL mode to require (enforce encryption) */
 PQsetConnOption(conn, "sslmode", "verify-full");

 /* Specify SSL certificate for client authentication */
 PQsetConnOption(conn, "sslcert", "/tmp/client-cert.pem");

 /* Specify private key for client certificate */
 PQsetConnOption(conn, "sslkey", "/tmp/client-key.pem");

 /* Specify root CA certificate to verify server */
 PQsetConnOption(conn, "sslrootcert", "/tmp/rds-ca-2019-root.pem");
}

/* Establish secure connection to cloud database */
PGconn *connect_secure_database(const DBConfig *config) {
 char conn_string[1024];
 PGconn *conn;

 /* Build connection string with security parameters */
 snprintf(conn_string, sizeof(conn_string),
 "host=%s port=%s dbname=%s user=%s password=%s "
 "sslmode=%s sslcert=%s sslkey=%s sslrootcert=%s "
 "connect_timeout=10",
 config->host,
 config->port,
 config->database,
 config->user,
 config->password,
 config->ssl_mode,
 config->ssl_cert,
 config->ssl_key,
 config->ssl_root_cert);

 /* Connect to database */
 conn = PQconnectdb(conn_string);

 /* Check connection status */
 if (PQstatus(conn) != CONNECTION_OK) {
 fprintf(stderr, "Connection failed: %s\n", PQerrorMessage(conn));
 PQfinish(conn);
 return NULL;
 }

 /* Verify SSL is actually being used */
 if (PQgetssl(conn) != NULL) {
 printf("✓ SSL encryption ACTIVE\n");
 printf(" SSL cipher: %s\n", SSL_get_cipher(PQgetssl(conn)));
 } else {
 fprintf(stderr, "Warning: Connection is NOT encrypted!\n");
 }

 return conn;
}

/* Execute secure parameterized query (prevents SQL injection) */
PGresult *execute_secure_query(PGconn *conn, const char *query, const char *param) {
 const char *param_values[1];
 param_values[0] = param;

 /* Use parameterized query to prevent SQL injection attacks */
 PGresult *res = PQexecParams(conn,
 query, /* Query with $1 placeholder */
 1, /* Number of parameters */
 NULL, /* Parameter types (auto-detect) */
 param_values, /* Parameter values */
 NULL, /* Parameter lengths */
 NULL, /* Parameter formats (text) */
 0); /* Result format (text) */

 if (PQresultStatus(res) != PGRES_TUPLES_OK) {
 fprintf(stderr, "Query failed: %s\n", PQerrorMessage(conn));
 PQclear(res);
 return NULL;
 }

 return res;
}

/* Demonstrate principle of least privilege */
void demonstrate_least_privilege(PGconn *conn) {
 printf("\n=== Principle of Least Privilege Demo ===\n");

 /* Create read-only user for application */
 const char *create_user_sql = 
 "CREATE ROLE app_readonly LOGIN PASSWORD 'secure_pass'; "
 "GRANT CONNECT ON DATABASE production_db TO app_readonly; "
 "GRANT SELECT ON ALL TABLES IN SCHEMA public TO app_readonly;";

 PGresult *res = PQexec(conn, create_user_sql);
 if (PQresultStatus(res) == PGRES_COMMAND_OK) {
 printf("✓ Created read-only user with minimal permissions\n");
 printf(" - Can only CONNECT to database\n");
 printf(" - Can only SELECT (not INSERT/UPDATE/DELETE)\n");
 }
 PQclear(res);
}

/* Main function demonstrating secure database connection */
int main(int argc, char *argv[]) {
 DBConfig config = {
 .host = "mydb.xyz.us-east-1.rds.amazonaws.com",
 .port = "5432",
 .database = "production_db",
 .user = "admin",
 .password = "", /* Would be from IAM token in production */
 .ssl_mode = "verify-full",
 .ssl_cert = "/tmp/client-cert.pem",
 .ssl_key = "/tmp/client-key.pem",
 .ssl_root_cert = "/tmp/rds-ca-2019-root.pem"
 };

 /* Initialize SSL library */
 init_ssl();

 printf("=== Secure Cloud Database Connection ===\n\n");

 /* Connect with SSL encryption */
 PGconn *conn = connect_secure_database(&config);
 if (conn == NULL) {
 fprintf(stderr, "Failed to connect to database\n");
 return 1;
 }

 printf("✓ Successfully connected to %s\n\n", config.host);

 /* Demonstrate SQL injection prevention */
 printf("=== SQL Injection Prevention Demo ===\n");
 const char *unsafe_query = "SELECT * FROM users WHERE id = ";
 const char *safe_query = "SELECT * FROM users WHERE id = $1";
 printf("Unsafe: %s user_input (vulnerable!)\n", unsafe_query);
 printf("Safe: %s (parameterized)\n", safe_query);
 printf("✓ Parameterized queries prevent SQL injection\n\n");

 /* Demonstrate least privilege */
 demonstrate_least_privilege(conn);

 /* Cleanup */
 PQfinish(conn);

 printf("\n=== Security Best Practices Demonstrated ===\n");
 printf("1. SSL/TLS encryption in transit\n");
 printf("2. Certificate verification (verify-full mode)\n");
 printf("3. Parameterized queries (SQL injection prevention)\n");
 printf("4. Principle of least privilege\n");

 return 0;
}
